class Solution:
    def maxTargetNodes(self, edges1, edges2, k):
        # independent re-derivation: literally attach each candidate bridge edge
        # and re-run a bounded breadth-first search from scratch every time
        from collections import deque
        n = len(edges1) + 1
        m = len(edges2) + 1
        adj1 = [[] for _ in range(n)]
        for a, b in edges1:
            adj1[a].append(b); adj1[b].append(a)
        adj2 = [[] for _ in range(m)]
        for a, b in edges2:
            adj2[a].append(b); adj2[b].append(a)
        def within(adj, src, limit):
            if limit < 0:
                return 0
            dist = {src: 0}
            q = deque([src])
            cnt = 0
            while q:
                u = q.popleft()
                if dist[u] <= limit:
                    cnt += 1
                else:
                    continue
                for v in adj[u]:
                    if v not in dist:
                        dist[v] = dist[u] + 1
                        q.append(v)
            return cnt
        best2 = max(within(adj2, j, k - 1) for j in range(m))
        return [within(adj1, i, k) + best2 for i in range(n)]

