from collections import deque
class Solution:
    def maxTargetNodes(self, edges1, edges2, k):
        def build(edges, n):
            adj = [[] for _ in range(n)]
            for a, b in edges:
                adj[a].append(b); adj[b].append(a)
            return adj
        def count_within(adj, src, limit):
            if limit < 0:
                return 0
            n = len(adj)
            dist = [-1] * n
            dist[src] = 0
            q = deque([src])
            cnt = 0
            while q:
                u = q.popleft()
                if dist[u] <= limit:
                    cnt += 1
                else:
                    continue
                for v in adj[u]:
                    if dist[v] == -1:
                        dist[v] = dist[u] + 1
                        q.append(v)
            return cnt
        n = len(edges1) + 1
        m = len(edges2) + 1
        adj1 = build(edges1, n)
        adj2 = build(edges2, m)
        cnt1 = [count_within(adj1, i, k) for i in range(n)]
        best2 = max(count_within(adj2, j, k - 1) for j in range(m))
        return [c + best2 for c in cnt1]

