var maxTargetNodes = function(edges1, edges2, k) {
    function buildAdj(edges, n) {
        const adj = Array.from({length: n}, () => []);
        for (const [a, b] of edges) { adj[a].push(b); adj[b].push(a); }
        return adj;
    }
    function countWithin(adj, src, limit) {
        if (limit < 0) return 0;
        const n = adj.length;
        const dist = new Array(n).fill(-1);
        dist[src] = 0;
        const queue = [src];
        let head = 0, cnt = 0;
        while (head < queue.length) {
            const u = queue[head++];
            if (dist[u] <= limit) cnt++; else continue;
            for (const v of adj[u]) {
                if (dist[v] === -1) { dist[v] = dist[u] + 1; queue.push(v); }
            }
        }
        return cnt;
    }
    const n = edges1.length + 1, m = edges2.length + 1;
    const adj1 = buildAdj(edges1, n), adj2 = buildAdj(edges2, m);
    const cnt1 = [];
    for (let i = 0; i < n; i++) cnt1.push(countWithin(adj1, i, k));
    let best2 = 0;
    for (let j = 0; j < m; j++) best2 = Math.max(best2, countWithin(adj2, j, k - 1));
    return cnt1.map(c => c + best2);
};
